onAddNewRowSave:
{{
  (async () => {
    const row = Table1Alimentos.newRow;

    // 1. Pegamos os valores brutos da linha
    const alimentoId = row?.ali002_alimentacao;
    const opcao = row?.ali002_opcao;
    const observacao = row?.ali002_observacao;

    // 2. Correção da Lógica para o campo PERMITIDO
    // Avaliamos se o valor vindo do Select é a string "false" ou o booleano false
    let permitido;
    if (row?.ali002_permitido === "false" || row?.ali002_permitido === false) {
      permitido = false;
    } else {
      permitido = true; // Default para "true" ou string "true"
    }

    // 3. Validação
    if (!alimentoId) {
      return showAlert("Selecione um alimento!", "warning");
    }

    const dados = {
      ali002_alimentacao: Number(alimentoId),
      ali002_opcao: opcao || 'O',
      ali002_observacao: observacao || '',
      ali002_permitido: permitido 
    };

    // 4. Execução
    await InsertPetAlimentacao.run(dados)
      .then(() => {
        showAlert("Alimento registrado com sucesso!", "success");
        SelectPetAlimentacao.run();
        resetWidget("Table1Alimentos", true); // O 'true' ajuda a resetar estados internos
      })
      .catch((err) => {
        showAlert("Erro ao salvar: " + err.message, "error");
      });
  })()
}}

EditActions1.onDiscard:
{{
  (async () => {
    // Reseta a tabela para o estado original dos dados
    // Isso limpa as edições pendentes e desabilita os botões de ação da linha
    await resetWidget("Table1Alimentos", true);

    showAlert("Alterações descartadas", "info");
  })()
}}

EditActions1.onSave:
{{
  (async () => {
    // Para Update, usamos triggeredRow para pegar a linha exata que foi clicada
    const row = Table1Alimentos.triggeredRow;

    // Captura dos valores (priorizando o que foi editado, senão mantém o original)
    const alimentoId = row?.ali002_alimentacao;
    const opcao = row?.ali002_opcao;
    const observacao = row?.ali002_observacao;

    // Lógica para o campo PERMITIDO (tratando String ou Booleano)
    const valorPermitido = row?.ali002_permitido;
    const permitido = (valorPermitido === "false" || valorPermitido === false) ? false : true;

    // ID do registro para saber QUAL linha atualizar no banco
    const idRegistro = row?.ali002_id;

    if (!idRegistro) {
      return showAlert("Erro: ID do registro não encontrado.", "error");
    }

    const dados = {
      ali002_id: idRegistro,
      ali002_alimentacao: Number(alimentoId),
      ali002_opcao: opcao || 'O',
      ali002_observacao: observacao || '',
      ali002_permitido: permitido 
    };

    // Executa a Query de Update
    await UpdatePetAlimentacao.run(dados)
      .then(() => {
        showAlert("Registro atualizado!", "success");
        SelectPetAlimentacao.run();
      })
      .catch((err) => {
        showAlert("Erro ao atualizar: " + err.message, "error");
      });
  })()
}}

